using System;using System.Windows;using System.Windows.Input;using ICSharpCode.WpfDesign;using ICSharpCode.WpfDesign.Designer.Services;namespace BgCommon.UI.Designer.DragDrop{    /// <summary>    /// 拖放管理器    /// </summary>    public class DragDropManager    {        private readonly DesignContext _context;        private MoveLogic _moveLogic;        private ChangeGroup _changeGroup;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public DragDropManager(DesignContext context)        {            _context = context;        }                /// <summary>        /// 初始化拖放管理器        /// </summary>        /// <param name="panel">设计面板</param>        public void Initialize(ICSharpCode.WpfDesign.Designer.IDesignPanel panel)        {            if (panel == null) return;                        // 注册拖放事件            panel.DragOver += OnDragOver;            panel.Drop += OnDrop;            panel.DragLeave += OnDragLeave;        }                /// <summary>        /// 处理拖放悬停事件        /// </summary>        /// <param name="sender">发送者</param>        /// <param name="e">拖放事件参数</param>        private void OnDragOver(object sender, DragEventArgs e)        {            try            {                var designPanel = (ICSharpCode.WpfDesign.Designer.IDesignPanel)sender;                e.Effects = DragDropEffects.None;                e.Handled = true;                                var position = e.GetPosition(designPanel);                                // 处理从工具箱拖放的元素                if (e.Data.GetDataPresent(typeof(Type))) {                    HandleToolboxDrag(designPanel, e, position);                }                // 处理设计面板内的元素拖放                else if (e.Data.GetDataPresent(typeof(DesignItem[]))) {                    HandleDesignItemDrag(designPanel, e, position);                }            }            catch (Exception ex)            {                DragDropExceptionHandler.RaiseUnhandledException(ex);            }        }                /// <summary>        /// 处理工具箱拖放        /// </summary>        /// <param name="panel">设计面板</param>        /// <param name="e">拖放事件参数</param>        /// <param name="position">位置</param>        private void HandleToolboxDrag(ICSharpCode.WpfDesign.Designer.IDesignPanel panel, DragEventArgs e, Point position)        {            var componentType = (Type)e.Data.GetData(typeof(Type));            if (componentType == null) return;                        if (_moveLogic == null)            {                // 开始创建组件                if (_changeGroup != null)                {                    _changeGroup.Abort();                    _changeGroup = null;                }                                _changeGroup = _context.RootItem.OpenGroup("Add Control");                panel.IsAdornerLayerHitTestVisible = false;                                var hitTestResult = panel.HitTest(position, false, true, ICSharpCode.WpfDesign.Designer.HitTestType.Default);                if (hitTestResult.ModelHit != null)                {                    panel.Focus();                                        // 创建组件                    var designItem = _context.Services.Component.CreateComponent(componentType);                    if (designItem != null)                    {                        // 添加到容器                        if (AddItemToContainer(hitTestResult.ModelHit, designItem))                        {                            _moveLogic = new MoveLogic(designItem);                            _moveLogic.Start(position);                            e.Effects = DragDropEffects.Copy;                        }                        else                        {                            _changeGroup.Abort();                            _changeGroup = null;                        }                    }                }            }            else if (_moveLogic.Operation != null)            {                // 移动组件                _moveLogic.Move(position);                e.Effects = DragDropEffects.Copy;            }        }                /// <summary>        /// 处理设计项拖放        /// </summary>        /// <param name="panel">设计面板</param>        /// <param name="e">拖放事件参数</param>        /// <param name="position">位置</param>        private void HandleDesignItemDrag(ICSharpCode.WpfDesign.Designer.IDesignPanel panel, DragEventArgs e, Point position)        {            var designItems = (DesignItem[])e.Data.GetData(typeof(DesignItem[]));            if (designItems == null || designItems.Length == 0) return;                        if (_moveLogic == null)            {                // 开始移动组件                if (_changeGroup != null)                {                    _changeGroup.Abort();                    _changeGroup = null;                }                                _changeGroup = _context.RootItem.OpenGroup("Move Controls");                panel.IsAdornerLayerHitTestVisible = false;                                var hitTestResult = panel.HitTest(position, false, true, ICSharpCode.WpfDesign.Designer.HitTestType.Default);                if (hitTestResult.ModelHit != null)                {                    panel.Focus();                                        _moveLogic = new MoveLogic(designItems[0]);                    _moveLogic.Start(position);                    e.Effects = DragDropEffects.Move;                }            }            else if (_moveLogic.Operation != null)            {                // 移动组件                _moveLogic.Move(position);                e.Effects = DragDropEffects.Move;            }        }                /// <summary>        /// 处理拖放事件        /// </summary>        /// <param name="sender">发送者</param>        /// <param name="e">拖放事件参数</param>        private void OnDrop(object sender, DragEventArgs e)        {            try            {                var designPanel = (ICSharpCode.WpfDesign.Designer.IDesignPanel)sender;                                if (_moveLogic != null)                {                    _moveLogic.Stop();                    designPanel.IsAdornerLayerHitTestVisible = true;                    _moveLogic = null;                                        if (_changeGroup != null)                    {                        _changeGroup.Commit();                        _changeGroup = null;                    }                                        e.Handled = true;                }            }            catch (Exception ex)            {                DragDropExceptionHandler.RaiseUnhandledException(ex);            }        }                /// <summary>        /// 处理拖放离开事件        /// </summary>        /// <param name="sender">发送者</param>        /// <param name="e">拖放事件参数</param>        private void OnDragLeave(object sender, DragEventArgs e)        {            try            {                var designPanel = (ICSharpCode.WpfDesign.Designer.IDesignPanel)sender;                                if (_moveLogic != null)                {                    _moveLogic.Cancel();                    designPanel.IsAdornerLayerHitTestVisible = true;                    _moveLogic = null;                                        if (_changeGroup != null)                    {                        _changeGroup.Abort();                        _changeGroup = null;                    }                }            }            catch (Exception ex)            {                DragDropExceptionHandler.RaiseUnhandledException(ex);            }        }                /// <summary>        /// 将项添加到容器        /// </summary>        /// <param name="container">容器</param>        /// <param name="item">要添加的项</param>        /// <returns>是否添加成功</returns>        private bool AddItemToContainer(DesignItem container, DesignItem item)        {            try            {                // 检查容器是否可以接受子项                if (container.CanAddChild(item))                {                    container.CollectionElements.Add(item);                    return true;                }                return false;            }            catch            {                return false;            }        }                /// <summary>        /// 启动拖放操作        /// </summary>        /// <param name="panel">设计面板</param>        /// <param name="items">要拖放的设计项</param>        /// <param name="e">鼠标事件参数</param>        public void StartDrag(ICSharpCode.WpfDesign.Designer.IDesignPanel panel, DesignItem[] items, MouseButtonEventArgs e)        {            if (items == null || items.Length == 0) return;                        // 开始拖放操作            DragDrop.DoDragDrop(panel, items, DragDropEffects.Move);        }    }}